 84	    if (!Array.isArray(body.Operations))
 85	        throw new InvalidScimPatchRequest('Operations should be an array.');
 86	
 87	    if (!body.Operations || body.Operations.length <= 0)
 88	        throw new InvalidScimPatchRequest('Missing operations.');
 89	
 90	    body.Operations.forEach(validatePatchOperation);
 91	}
