 93	/*
 94	 * This method apply patch operations on a SCIM Resource.
 95	 * @param scimResource The initial resource
 96	 * @param patchOperations An array of SCIM patch operations we want to apply on the scimResource object.
 97	 * @param options Options to customize some behaviour of scimPatch
 98	 * @return the scimResource patched.
 99	 * @throws {InvalidScimPatchOp} if the patch could not happen.
100	 */
101	export function scimPatch<T extends ScimResource>(scimResource: T, patchOperations: Array<ScimPatchOperation>,
102	                                                  options: ScimPatchOptions = {mutateDocument: true, treatMissingAsAdd: true}): T {
103	    if (!options.mutateDocument) {
104	        // Deeply clone the object.
105	        // https://jsperf.com/deep-copy-vs-json-stringify-json-parse/25 (recursiveDeepCopy)
106	        scimResource = JSON.parse(JSON.stringify(scimResource));
107	    }
108	
109	    return patchOperations.reduce((patchedResource, patch) => {
110	        switch (patch.op) {
111	            case 'remove':
112	            case 'Remove':
113	                return applyRemoveOperation(patchedResource, patch);
114	            case 'add':
115	            case 'Add':
116	            case 'replace':
117	            case 'Replace':
118	                return applyAddOrReplaceOperation(patchedResource, patch, !!options.treatMissingAsAdd);
119	            default:
120	                throw new InvalidScimPatchRequest(`Operator is invalid for SCIM patch request. ${patch}`);
121	        }
122	    }, scimResource);
123	}
