219	function applyAddOrReplaceOperation<T extends ScimResource>(scimResource: T, patch: ScimPatchAddReplaceOperation, treatMissingAsAdd: boolean): T {
220	    // We manipulate the object directly without knowing his property, that's why we use any.
221	    // let resource: Record<string, any> = scimResource;
222	    let resources_scoped: Record<string, any>[];
223	    validatePatchOperation(patch);
224	
225	    if (!patch.path)
226	        return addOrReplaceAttribute(scimResource, patch);
227	
228	    // We navigate till the second to last of the path.
229	    const paths = resolvePaths(patch.path);
230	    const lastSubPath = paths[paths.length - 1];
231	
232	    try {
233	        resources_scoped = navigate(scimResource, paths);
234	    } catch(e) {
235	        if (e instanceof FilterOnEmptyArray || e instanceof FilterArrayTargetNotFound) {
236	            const resource: Record<string, any> = e.schema;
237	            // check issue https://github.com/thomaspoignant/scim-patch/issues/42 to see why we should add this
238	            const parsedPath = parse(e.valuePath);
239	            if (isAddOperation(patch.op) &&
240	              "compValue" in parsedPath &&
241	              parsedPath.compValue !== undefined &&
242	              parsedPath.op === "eq"
243	            ) {
244	                const result: any = {};
245	                result[parsedPath.attrPath] = parsedPath.compValue;
246	                result[lastSubPath] = addOrReplaceAttribute(undefined, patch, true);
247	                resource[e.attrName] = [...(resource[e.attrName] ?? []), result];
248	                return scimResource;
249	            } else if (
250	              treatMissingAsAdd &&
251	              isReplaceOperation(patch.op) &&
252	              "compValue" in parsedPath &&
253	              parsedPath.compValue !== undefined &&
254	              parsedPath.op === "eq"
255	            ) {
256	              // If the target location path specifies an attribute that does not
257	              // exist, the service provider SHALL treat the operation as an "add".
258	              return applyAddOrReplaceOperation(
259	                scimResource,
260	                { ...patch, op: "add" },
261	                false
262	              );
263	            }
264	            throw new NoTarget(patch.path);
265	        }
266	        throw e;
267	    }
268	    if (!IS_ARRAY_SEARCH.test(lastSubPath)) {
269	        for (const resource of resources_scoped) {
270	            resource[lastSubPath] = addOrReplaceAttribute(resource[lastSubPath], patch);
271	        }
272	        return scimResource;   
273	    }
274	
275	    
276	
277	    // The last element is an Array request.
278	    for (const resource of resources_scoped) {
279	        
280	        const {valuePath, array} = extractArray(lastSubPath, resource);
281	
282	        // Get the list of items who are successful for the search query.
283	        const matchFilter = filterWithQuery<any>(array, valuePath);
284	
285	        // If the target location is a multi-valued attribute for which a value selection filter ("valuePath") has been
286	        // supplied and no record match was made, the service provider SHALL indicate failure by returning HTTP status
287	        // code 400 and a "scimType" error code of "noTarget".
288	        if (isReplaceOperation(patch.op) && matchFilter.length === 0) {
289	            throw new NoTarget(patch.path);
290	        }
291	        for (let i = 0; i < array.length; i++) {
292	            // We are sure to find at least one index because matchFilter comes from array.
293	            if(matchFilter.includes(array[i])){
294	                array[i] = addOrReplaceAttribute(array[i], patch);
295	            }
296	        }
297	    }
298	
299	    return scimResource;
300	}
