323	/**
324	 * navigate allow to get the sub object who want to edit with the patch operation.
325	 * @param inputSchema the initial ScimResource
326	 * @param paths an Array who contains the path of the sub object
327	 * @param options options used while calling navigate
328	 * @return the parent object of the element we want to edit
329	 */
330	function navigate(inputSchema: any, paths: string[], options: NavigateOptions = {}): Record<string, unknown>[] {
331	    let schemas: any[] = [inputSchema];
332	    for (let i = 0; i < paths.length - 1; i++) {
333	        const subPath = paths[i];
334	
335	        // We check if the element is an array with query (ex: emails[primary eq true).
336	        if (IS_ARRAY_SEARCH.test(subPath)) {           
337	            schemas = schemas.flatMap((schema)=>{ 
338	                try {
339	                    const {attrName, valuePath, array} = extractArray(subPath, schema);
340	                    // Get the item who is successful for the search query.
341	                    const matchFilter = filterWithQuery<any>(array, valuePath);
342	                    if (matchFilter.length === 0) {
343	                        throw new FilterArrayTargetNotFound('A matching array entry was not found using the supplied filter.', attrName, valuePath, schema);
344	                    }
345	                    return matchFilter;
346	                } catch (error) {
347	                    /*
348	                        FIXME In some edge cases, not fully compliant with SCIM, this can prematurely throw en error
349	                        For example if we have a structure with multiValued complex
350	                        attribute inside of a multiValued complex attribute, in
351	                        this case this throw even if only a "branch" of the search fail.
352	                    */
353	                    if(error instanceof FilterOnEmptyArray){
354	                        error.schema = schema;
355	                    }
356	                    throw error;
357	                }
358	            });
359	        } else {
360	            schemas = schemas.flatMap((schema)=>{
361	                if (!schema[subPath] && options.isRemoveOp)
362	                    throw new InvalidRemoveOpPath();
