 74	/*
 75	 * PatchBodyValidation validate if the request body of the SCIM Patch is valid.
 76	 * If the body is not valid the function throw an error.
 77	 * @param body data from the patch request.
 78	 * @throws {InvalidScimPatchRequest} if one operation is not valid.
 79	 * @throws {NoPathInScimPatchOp} if one operation is a remove with no path.
 80	 */
 81	export function patchBodyValidation(body: ScimPatch): void {
 82	    if (!body.schemas || !body.schemas.includes(PATCH_OPERATION_SCHEMA))
 83	        throw new InvalidScimPatchRequest('Missing schemas.');
 84	
 85	    if (!Array.isArray(body.Operations))
 86	        throw new InvalidScimPatchRequest('Operations should be an array.');
 87	
 88	    if (!body.Operations || body.Operations.length <= 0)
 89	        throw new InvalidScimPatchRequest('Missing operations.');
 90	
 91	    body.Operations.forEach(validatePatchOperation);
