 98	 * @param options Options to customize some behaviour of scimPatch
 99	 * @return the scimResource patched.
100	 * @throws {InvalidScimPatchOp} if the patch could not happen.
101	 */
102	export function scimPatch<T extends ScimResource>(scimResource: T, patchOperations: Array<ScimPatchOperation>,
103	                                                  options: ScimPatchOptions = {mutateDocument: true, treatMissingAsAdd: true}): T {
104	    if (!options.mutateDocument) {
105	        // Deeply clone the object.
106	        // https://jsperf.com/deep-copy-vs-json-stringify-json-parse/25 (recursiveDeepCopy)
107	        scimResource = JSON.parse(JSON.stringify(scimResource));
108	    }
109	
110	    return patchOperations.reduce((patchedResource, patch) => {
111	        switch (patch.op) {
112	            case 'remove':
113	            case 'Remove':
114	                return applyRemoveOperation(patchedResource, patch);
115	            case 'add':
116	            case 'Add':
117	            case 'replace':
118	            case 'Replace':
119	                return applyAddOrReplaceOperation(patchedResource, patch, !!options.treatMissingAsAdd);
120	            default:
121	                throw new InvalidScimPatchRequest(`Operator is invalid for SCIM patch request. ${patch}`);
