440	 * @param obj the object where we should the key
441	 * @param keyPath an array which represent the path of the nested object
442	 * @param value value to assign
443	 * @param op patch operation
444	 */
445	function assign(obj:any, keyPath:Array<string>, value:any, op: string) {
446	    validatePathSegments(keyPath);
447	
448	    const lastKeyIndex = keyPath.length-1;
449	    for (let i = 0; i < lastKeyIndex; ++ i) {
450	        const key = keyPath[i];
451	        if (!Object.prototype.hasOwnProperty.call(obj, key)){
452	            obj[key] = {};
453	        }
454	        obj = obj[key];
455	    }
456	
457	    // If the attribute is an array and the operation is "add",
458	    // then the value should be added to the array
459	    const attribute = obj[keyPath[lastKeyIndex]];
460	    if (isAddOperation(op) && Array.isArray(attribute)) {
461	        // If the value is also an array, append all values of the array to the attribute
462	        if (Array.isArray(value)) {
463	            obj[keyPath[lastKeyIndex]] = [...attribute, ...value];
464	            return;
465	        }
466	
467	        // If value is not an array, simply append it as a whole to end of attribute
468	        obj[keyPath[lastKeyIndex]] = [...attribute, value];
469	        return;
470	    }
471	    obj[keyPath[lastKeyIndex]] = value;
472	}
