474	/**
475	 * Return the items in the array who match the filter.
476	 * @param arr the collection where we are searching.
477	 * @param querySearch the search request.
478	 * @param options options used while calling filterWithQuery
479	 * @return an array who contains the search results.
480	 */
481	function filterWithQuery<T>(arr: Array<T>, querySearch: string,
482	                            options: FilterWithQueryOptions = ({} as FilterWithQueryOptions)): Array<T> {
483	    try {
484	        const f = filter(parse(querySearch));
485	        return arr.filter(e => options.excludeIfMatchFilter ? !f(e) : f(e));
486	    } catch (error) {
487	        throw new InvalidScimPatchOp(`${error}`);
488	    }
489	}
490	
491	/**
492	 * Return the array without items supplied in .
493	 * @param arr the collection where we are searching.
494	 * @param itemsToRemove array with items to remove from original.
495	 * @return an array which contains the search results.
496	 */
497	function removeWithPatchValue<T>(arr: Array<T>, itemsToRemove: Array<T> | Record<string, any> | string | number): T[] {
498	    if (!Array.isArray(arr))
499	        throw new RemoveValueNotArray();
500	
501	    // patch value is a single item, we remove from the array all the similar items.
502	    if (!Array.isArray(itemsToRemove))
503	        return arr.filter(item => !deepEqual(itemsToRemove, item));
504	
505	    // Sometimes the patch value is an array (this is how it works with one-login, ex: [{"test":true}])
506	    // We iterate on all the values in the array to delete them all.
507	    itemsToRemove.forEach(toRemove => {
508	       if (Array.isArray(toRemove))
509	           throw new RemoveValueNestedArrayNotSupported();
510	
511	       arr = arr.filter(item => !deepEqual(toRemove, item));
512	    });
513	
514	    return arr;
515	}
