517	/**
518	 * deepIncludes has similar behaviour as Array.prototype.includes,
519	 * just that instead of === for equality check, it uses deepEqual library
520	 * @param array the array on which inclusion check has to be performed
521	 * @param item the item whose inclusion has to be checked
522	 * @returns true if the item is present, else false
523	 */
524	function deepIncludes(array: any[], item: any): boolean {
525	    return array.some(el => deepEqual(item, el));
526	}
527	
528	function isValidOperation(operation: string): boolean {
529	    return AUTHORIZED_OPERATION.includes(operation.toLowerCase());
530	}
531	
532	function validatePathSegments(paths: string[]): void {
533	    paths.forEach(validatePathSegment);
534	}
